const DENSE_B = [0xaeb690,0xb0cdb8,-0x7c5fd8,-0xa125e8];

function predict20x20(image, p = 15, useInterleaved = false, negativeDiv = 2) {
  const outSize = 9;
  const numFilters = 2;
  const convOut = Array(numFilters).fill(0).map(() => Array(outSize).fill(0).map(() => Array(outSize).fill(0)));
  const stride = 2;

  for (let f = 0; f < numFilters; f++) {
    for (let i = 0; i < outSize; i++) {
        for (let j = 0; j < outSize; j++) {
            let sum = CONV_B[f];
            for (let c = 0; c < 3; c++) {
                for (let ki = 0; ki < 3; ki++) {
                    for (let kj = 0; kj < 3; kj++) {
                        const r = i * stride + ki;
                        const col = j * stride + kj;
                        if (r < 20 && col < 20) {
                            sum += image[c][r][col] * CONV_W[ki][kj][c][f];
                        }
                    }
                }
            }
            if (sum < 0) sum = Math.trunc(sum / negativeDiv);
            convOut[f][i][j] = Math.trunc(sum / Math.pow(2, p));
        }
    }
  }

  const flattened = [];
  if (useInterleaved) {
      const flat = new Array(162);
      for (let f = 0; f < numFilters; f++) {
        for (let i = 0; i < outSize; i++) {
            for (let j = 0; j < outSize; j++) {
                const index = f + i * numFilters * outSize + j * numFilters;
                flat[index] = convOut[f][i][j];
            }
        }
      }
      flattened.push(...flat);
  } else {
      for (let f = 0; f < numFilters; f++) {
        for (let i = 0; i < outSize; i++) {
            for (let j = 0; j < outSize; j++) {
                flattened.push(convOut[f][i][j]);
            }
        }
      }
  }

  const out = [];
  for (let i = 0; i < 4; i++) {
    let sum = DENSE_B[i];
    for (let j = 0; j < 162; j++) {
        sum += flattened[j] * DENSE_W[i][j];
    }
    out.push(Math.trunc(sum / Math.pow(2, p)));
  }
  return out;
}

const PRIME = BigInt("21888242871839275222246405745257275088548364400416034343698204186575808495617");

async function run() {
    const wasmPath = path.join(__dirname, 'public/model.wasm');
    const wcPath = path.join(__dirname, 'compiled_circuit/model_circom/model_js/witness_calculator.js');
    
    // Load witness calculator manually to avoid ESM issues
    const wcBuffer = fs.readFileSync(wcPath);
    const wcCode = wcBuffer.toString();
    const builder = new Function('module', 'exports', wcCode);
    const mockModule = { exports: {} };
    builder(mockModule, mockModule.exports);
    const witnessCalculator = await mockModule.exports(fs.readFileSync(wasmPath));

    const image = Array(3).fill(0).map((_, c) => 
        Array(20).fill(0).map((_, r) => 
            Array(20).fill(0).map((_, col) => (c * 61 + r * 17 + col * 7) % 256)
        )
    );
    const quantizedImage = image.map(c => c.map(r => r.map(p => Math.round((p / 255.0) * 32768))));

    console.log("NeuroSync Ultra-Fast Audit [Witness Mode]...");
    
    const input = {
        image: quantizedImage,
        address: "0",
        threshold: "1000000000",
        nonce: "123",
        features: ["0", "0", "0", "0"]
    };

    try {
        const witness = await witnessCalculator.calculateWitness(input, 0);
        
        // Find Ground Truth Features (Assume 1391 start based on previous turn's extraction)
        // Let's print a small range around 1390 to be SURE.
        const wasmFeatures = [];
        for (let i = 0; i < 4; i++) {
            let val = witness[1391 + i];
            if (val > PRIME / 2n) val -= PRIME;
            wasmFeatures.push(Number(val));
        }
        console.log("WASM (Ground Truth):", wasmFeatures);

        const candidates = [
            { id: "Seq, Slope 2", features: predict20x20(quantizedImage, 15, false, 2) },
            { id: "Seq, Slope 4", features: predict20x20(quantizedImage, 15, false, 4) },
            { id: "Int, Slope 2", features: predict20x20(quantizedImage, 15, true, 2) },
            { id: "Int, Slope 4", features: predict20x20(quantizedImage, 15, true, 4) }
        ];

        for (const c of candidates) {
            const matches = JSON.stringify(c.features) === JSON.stringify(wasmFeatures);
            console.log(`[${c.id}] ${matches ? "✅ MATCHED!!!" : "❌ FAIL"}`);
            if (!matches) {
                console.log(`   Result: ${JSON.stringify(c.features)}`);
            }
        }
    } catch (err) {
        console.error("Audit Fail:", err);
    }
}

run();
